const exec = $json.execution || {};
const wf = $json.workflow || {};
const err = exec.error || {};

const message = err.message || '(no error message)';
const errorText = `${message}\n${err.stack || ''}`.toLowerCase();

// n8n's built-in retryOnFail (configured per-node on the HTTP/Postgres
// nodes in workflows 01-04) already retries transient errors with a fixed
// backoff before a workflow fails permanently -- by the time this trigger
// fires, any such retries are exhausted. This classification is
// informational only (shown in the Slack alert), it does not drive further
// retries here.
const transientPattern = /(timeout|timed out|econnreset|econnrefused|rate limit|429|502|503|504)/;
const errorClass = transientPattern.test(errorText) ? 'transient (retries exhausted)' : 'permanent';

return [{
  json: {
    workflow_name: wf.name || 'unknown workflow',
    workflow_id: wf.id || null,
    failed_node: exec.lastNodeExecuted || 'unknown node',
    error_message: message,
    error_class: errorClass,
    execution_id: exec.id || null,
    execution_url: exec.url || null,
    occurred_at: new Date().toISOString(),
  },
}];

const ctx = $json;
return [{
  json: {
    ...ctx,
    event_payload: JSON.stringify({
      workflow_name: ctx.workflow_name,
      workflow_id: ctx.workflow_id,
      failed_node: ctx.failed_node,
      error_message: ctx.error_message,
      error_class: ctx.error_class,
      execution_id: ctx.execution_id,
      execution_url: ctx.execution_url,
      occurred_at: ctx.occurred_at,
    }),
  },
}];

const ctx = $('Parse Error Context').item.json;

const lines = [
  `:rotating_light: *Anchor workflow failure* (${ctx.error_class})`,
  `Workflow: *${ctx.workflow_name}*`,
  `Failed node: *${ctx.failed_node}*`,
  `Error: ${ctx.error_message}`,
  ctx.execution_url ? `Execution: ${ctx.execution_url}` : null,
  '',
  'Open the execution above to check for an affected application_id. If an ' +
    'application is stuck because of this, mark it manually:',
  "`UPDATE application SET status = 'errored' WHERE id = '<application_id>';`",
].filter(Boolean);

return [{ json: { slack_text: lines.join('\n') } }];
